import java.io.File;
import java.io.IOException;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.ParserConfigurationException;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.Node;
import org.w3c.dom.NodeList;
import org.xml.sax.SAXException;

public class ConfigParser {
    public static Map<String, String> parseConfig(File configFile) throws ParserConfigurationException, SAXException, IOException {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document document = builder.parse(configFile);

        NodeList nodes = document.getElementsByTagName("setting");

        Map<String, String> configMap = new HashMap<>();

        for (int i = 0; i < nodes.getLength(); i++) {
            Node node = nodes.item(i);
            if (node.getNodeType() == Node.ELEMENT_NODE) {
                Element element = (Element) node;
                NodeList children = element.getChildNodes();

                String key = element.getTagName();
                String value = "";

                for (int j = 0; j < children.getLength(); j++) {
                    Node childNode = children.item(j);
                    if (childNode.getNodeType() == Node.ELEMENT_NODE) {
                        Element childElement = (Element) childNode;
                        if ("value".equals(childElement.getTagName())) {
                            value = childElement.getTextContent();
                            if (!value.startsWith("&") && !value.endsWith(";")) {
                                continue;
                            }
                            try {
                                Document tempDoc = builder.parse(new StringReader(value));
                                Element root = tempDoc.getDocumentElement();
                                NodeList settingsList = root.getElementsByTagName("setting");
                                for (int k = 0; k < settingsList.getLength(); k++) {
                                    Node settingNode = settingsList.item(k);
                                    if (settingNode.getNodeType() == Node.ELEMENT_NODE) {
                                        Element settingElement = (Element) settingNode;
                                        String entityReference = settingElement.getAttribute("entity");
                                        if (entityReference.isEmpty()) {
                                            continue;
                                        }
                                        Document referencedDoc = builder.parse(new File(entityReference));
                                        NodeList referencedNodes = referencedDoc.getElementsByTagName("setting");
                                        for (int l = 0; l < referencedNodes.getLength(); l++) {
                                            Node referencedNode = referencedNodes.item(l);
                                            if (referencedNode.getNodeType() == Node.ELEMENT_NODE) {
                                                Element referencedElement = (Element) referencedNode;
                                                String referredKey = referencedElement.getTagName();
                                                configMap.put(referredKey, settingElement.getTextContent());
                                            }
                                        }
                                    }
                                }
                            } catch (Exception e) {}
                        }
                    }
                }
                if (!value.isEmpty()) {
                    configMap.put(key, value);
                }
            }
        }

        return configMap;
    }
}